stations.forEach(station => {
    if (Array.isArray(station.modules)) {
        station.modules.forEach(mod => {
            if (mod.id) {
                assignedModules.add(mod.id);
            }
        });
    }
});

// Step 2: Clean up pendingModules by removing any that are already assigned
for (let mod of pendingModules) {
    if (assignedModules.has(mod)) {
        pendingModules.delete(mod);
    }
}

// Step 3: Now handle the current msg.module
