    station.modules && station.modules.some(module => module.id === moduleId)
);

if (matchedStation) {
    msg.stationid = matchedStation.stationid;
} else {
    msg.stationid = "pending";
    pendingModules.add(moduleId);
}

// Save the updated pending list back to global
global.set("pending_modules", Array.from(pendingModules));

// Return the result
return msg;

