}

function parseHoleEjectionPayload(data) {
    // If data is a string, assume it's a hex string and convert to a byte array
    if (typeof data === 'string') {
        data = hexStringToByteArray(data);
    } else if (!Array.isArray(data)) {
        data = Array.from(data);
    }

    // Log the converted payload for debugging
    node.warn("Converted payload: " + JSON.stringify(data));

    // Parse the fields
    const header = data[0];
    const length = (data[1] << 8) + data[2]; // big-endian conversion
    const command = data[3];
    const movementAddress = data[4];
    const hole = data[5];
    const ejectStatus = data[6];
    const extraField = data[7]; // Reserved or calibration/complement field
    const checksum = data[8];

    return {
        header,
        length,
        command,
        movementAddress,
        hole,
        ejectStatus,
        extraField,
        checksum
    };
}

