let allSlots = [];

for (let i = 0; i < 12; i++) {
    const moduleOffset = i * 66;
    const moduleBlock = data.slice(moduleOffset, moduleOffset + 66);

    if (moduleBlock.length < 66) {
        node.warn(`Module ${i + 1} is incomplete`);
        continue;
