    const chargersBytes = moduleBlock.slice(6); // skip module header

    for (let j = 0; j < 4; j++) {
        const offset = j * 15;
        const bytes = chargersBytes.slice(offset, offset + 15);

        if (bytes.length < 15) {
            node.warn(`Module ${i + 1} Slot ${j + 1} is incomplete`);
            continue;
        }

        const sn = getChargerSN(bytes.slice(5, 9));

        allSlots.push({
            position:         bytes[0],
            status:           bytes[1],
            dischargeCurrent: bytes[2],
            cellVoltage:      bytes[3],
            areaCode:         bytes[4],
            sn,
            batteryLevel:     bytes[9],
            temperature:      bytes[10],
            chargingVoltage:  bytes[11],
