let totalCount    = 0;
let fullCount     = 0;
let emptyCount    = 0;
let slotCountFree = 0;
let chargingCount = 0;

moduleObj.slots.forEach(s => {
    if (s.status === 1) {
        totalCount++;
        // Correctly increment full vs empty
        if (s.batteryLevel >= 80) {
            fullCount++;
        } else {
            emptyCount++;
        }
    } else if (s.status === 0) {
        slotCountFree++;
    }
    if (s.chargeCurrent > 0) chargingCount++;
});

moduleObj.total    = totalCount;
moduleObj.full     = fullCount;
moduleObj.empty    = emptyCount;
moduleObj.slot     = slotCountFree;
moduleObj.charging = chargingCount;

